<template>
  <graduados-app
    header-title="Búsqueda laboral"
    :header-show-back-button="true"
    body="white"
  >
    <div v-if="loading">
      <ion-thumbnail
        style="width: 100%; height: 15vh"
        class="ion-margin-bottom"
      >
        <ion-skeleton-text
          :animated="true"
          style="width: 100%; height: 15vh"
        ></ion-skeleton-text>
      </ion-thumbnail>

      <ion-skeleton-text
        :animated="true"
        style="width: 100%; height: 20px"
      ></ion-skeleton-text>
      <ion-skeleton-text
        :animated="true"
        style="width: 40%; height: 20px"
      ></ion-skeleton-text>

      <div class="ion-padding-top">
        <ion-skeleton-text
          :animated="true"
          style="width: 100%"
          v-for="i in [1, 2, 3, 4, 5, 6]"
          :key="i"
        ></ion-skeleton-text>
        <ion-skeleton-text
          :animated="true"
          style="width: 20%"
        ></ion-skeleton-text>
      </div>
    </div>

    <div v-if="!loading && job">
      <ion-thumbnail class="ion-margin-bottom">
        <ion-img src="/assets/jobs/job.png"></ion-img>
      </ion-thumbnail>

      <ion-text
        ><h3>{{ job.title }}</h3></ion-text
      >

      <div class="tabs">
        <div
          class="tab"
          :class="{ selected: tab == 'information' }"
          @click="tab = 'information'"
        >
          Información
        </div>
        <div
          class="tab"
          :class="{ selected: tab == 'requirements' }"
          @click="tab = 'requirements'"
        >
          Requisitos
        </div>
        <div
          class="tab"
          :class="{ selected: tab == 'about' }"
          @click="tab = 'about'"
        >
          La empresa
        </div>
        <div
          class="tab"
          :class="{ selected: tab == 'contact' }"
          @click="tab = 'contact'"
        >
          Contacto
        </div>
      </div>

      <div class="ion-padding-top ion-margin-top content">
        <template v-if="tab == 'information'">
          <ion-text>
            <!-- <p><strong>Posición: </strong> {{ job.title }}</p> -->
            <p><strong>Compañía: </strong> {{ job.company }}</p>
            <p>
              <strong>Descripción: </strong>
              <span v-html="job.description"></span>
            </p>
            <p><strong>Duración: </strong> {{ job.duration }}</p>
          </ion-text>
        </template>
        <template v-if="tab == 'requirements'">
          <ion-text>
            <p><strong>Sexo: </strong> {{ job.gender }}</p>
            <p><strong>Edad: </strong> {{ job.age_from }} a {{ job.age_to }}</p>
            <p><strong>Lugar de residencia: </strong> {{ job.residency }}</p>
            <p><strong>Experiencia: </strong> {{ job.experience }}</p>
            <p v-if="job.languages.length > 0">
              <strong>Idiomas: </strong> {{ job.languages_string }}
            </p>
            <p><strong>Nivel educativo: </strong> {{ job.education_level }}</p>
            <p v-if="job.show_salary">
              <strong>Salario: </strong> {{ job.salary_string }}
            </p>
          </ion-text>
        </template>
        <template v-if="tab == 'about'">
          <ion-text>
            <!-- <p><strong>País: </strong> {{ job.country }}</p> -->
            <p><strong>Provincia: </strong> {{ job.province }}</p>
            <p><strong>Ciudad: </strong> {{ job.city }}</p>
            <p><strong>Jerarquía: </strong> {{ job.position }}</p>
            <p><strong>Modalidad: </strong> {{ job.modality }}</p>
            <p><strong>Cant. vacantes: </strong> {{ job.vacancies_amount }}</p>
          </ion-text>
        </template>
        <template v-if="tab == 'contact'">
          <ion-text>
            <div v-if="job.phone || job.email" class="contact-info">
              <h4>📞 Información de contacto</h4>
              <div v-if="job.phone" class="contact-item">
                <p>
                  <strong>Teléfono: </strong>
                  <a :href="`tel:${job.phone}`" class="contact-link">{{
                    job.phone
                  }}</a>
                </p>
              </div>
              <div v-if="job.email" class="contact-item">
                <p>
                  <strong>Email: </strong>
                  <a :href="`mailto:${job.email}`" class="contact-link">{{
                    job.email
                  }}</a>
                </p>
              </div>
              <p class="contact-note">
                <small
                  >💡 También puedes usar el botón "Contactar" para comunicarte
                  directamente.</small
                >
              </p>
            </div>
            <div v-else class="no-contact">
              <p>
                ℹ️ No hay información de contacto disponible para esta
                publicación.
              </p>
            </div>
          </ion-text>
        </template>
      </div>

      <!-- Componente de compartir social -->
      <SocialShare
        v-if="job && !loading"
        :share-data="{
          title: job.title,
          text: `Compañía: ${job.company} - ${
            job.description
              ? job.description.replace(/<[^>]*>/g, '').substring(0, 100) +
                '...'
              : ''
          }`,
          type: 'empleo',
          id: job.id,
        }"
      />
    </div>

    <template #footer v-if="!loading && !job.from_auth">
      <ion-button
        class="ion-margin-bottom"
        color="primary"
        shape="round"
        expand="full"
        @click="contact"
        >Contactar</ion-button
      >
      <ion-button
        v-if="!job.has_user_favorite"
        color="light-primary"
        shape="round"
        @click="saveFavorite"
        expand="full"
        >Guardar en favoritos</ion-button
      >
      <ion-button
        v-else
        color="light-primary"
        shape="round"
        expand="full"
        @click="removeFavorite"
        >Eliminar de favoritos</ion-button
      >
    </template>
  </graduados-app>
</template>

<script setup lang="ts">
import {
  IonThumbnail,
  IonText,
  IonImg,
  IonSkeletonText,
  IonButton,
} from "@ionic/vue";
import { ref, onMounted } from "vue";
import { useStore } from "vuex";
import { useRoute } from "vue-router";
import SocialShare from "@/components/SocialShare.vue";

const loading = ref(true);
const route = useRoute();
const store = useStore();
const job = ref<any>({});
const tab = ref("information");

onMounted(() => {
  const id = route.params.slug;
  store
    .dispatch("jobs/fetch", id)
    .then((response) => {
      job.value = response.data.data;
    })
    .finally(() => (loading.value = false));
});

function contact() {
  const contactOptions: Array<{ text: string; handler: () => void }> = [];

  // Priorizar teléfono si está disponible
  if (job.value.phone) {
    contactOptions.push({
      text: `📞 Llamar: ${job.value.phone}`,
      handler: () => {
        window.open(`tel:${job.value.phone}`, "_system");
      },
    });
  }

  // Agregar email si está disponible
  if (job.value.email) {
    contactOptions.push({
      text: `📧 Enviar email: ${job.value.email}`,
      handler: () => {
        window.open(`mailto:${job.value.email}`, "_system");
      },
    });
  }

  // Si no hay opciones de contacto
  if (contactOptions.length === 0) {
    store.dispatch(
      "ui/toastr/create",
      "No hay información de contacto disponible"
    );
    return;
  }

  // Si solo hay una opción, ejecutarla directamente
  if (contactOptions.length === 1) {
    contactOptions[0].handler();
    return;
  }

  // Si hay múltiples opciones, mostrar menú
  store.dispatch("ui/action/show", contactOptions);
}

function saveFavorite() {
  console.log("🔍 [MOBILE DEBUG] Iniciando saveFavorite");

  store
    .dispatch("jobs/addFavorite", job.value.id)
    .then((response) => {
      console.log("✅ [MOBILE DEBUG] Respuesta exitosa:", response);
      job.value.has_user_favorite = true;
      store.dispatch("ui/toastr/create", "Búsqueda guardada ✓");
    })
    .catch((error) => {
      console.error("❌ [MOBILE DEBUG] Error:", error);
      console.error("❌ [MOBILE DEBUG] Error status:", error.response?.status);

      // Solo mostrar mensaje específico para error 419, sin retry
      if (error.response?.status === 419) {
        store.dispatch(
          "ui/toastr/create",
          "Error de sesión. Intenta reloguearte."
        );
      } else if (error.response?.status === 401) {
        store.dispatch(
          "ui/toastr/create",
          "Sesión expirada. Inicia sesión nuevamente."
        );
      } else {
        store.dispatch(
          "ui/toastr/create",
          `Error: ${error.response?.status || error.message}`
        );
      }
    });
}

function removeFavorite() {
  console.log("🔍 [MOBILE DEBUG] Iniciando removeFavorite");

  store
    .dispatch("jobs/removeFavorite", job.value.id)
    .then((response) => {
      console.log("✅ [MOBILE DEBUG] Remove exitoso:", response);
      job.value.has_user_favorite = false;
      store.dispatch("ui/toastr/create", "Búsqueda eliminada de favoritos ✓");
    })
    .catch((error) => {
      console.error("❌ [MOBILE DEBUG] Error en remove:", error);
      console.error("❌ [MOBILE DEBUG] Error status:", error.response?.status);

      if (error.response?.status === 419) {
        store.dispatch(
          "ui/toastr/create",
          "Error de sesión. Intenta reloguearte."
        );
      } else if (error.response?.status === 401) {
        store.dispatch(
          "ui/toastr/create",
          "Sesión expirada. Inicia sesión nuevamente."
        );
      } else {
        store.dispatch(
          "ui/toastr/create",
          `Error: ${error.response?.status || error.message}`
        );
      }
    });
}
</script>

